import{_ as e,o as t,c as a,Q as o}from"./chunks/framework.c4d6cd72.js";const g=JSON.parse('{"title":"Downloading fraud data","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials-web/downloading-fraud-data.md","filePath":"tutorials-web/downloading-fraud-data.md"}'),r={name:"tutorials-web/downloading-fraud-data.md"},n=o('<h1 id="downloading-fraud-data" tabindex="-1">Downloading fraud data <a class="header-anchor" href="#downloading-fraud-data" aria-label="Permalink to &quot;Downloading fraud data&quot;">​</a></h1><p>To download fraud event data via FIB Web UI, perform the following steps:</p><ol><li>From the top right menu, select <strong>Download</strong>.</li><li>On the <strong>Download Fraud Data</strong> screen that appears, specify the following data: <ul><li><strong>Select Fraud Type</strong> dropdown menu — select the fraud type of the fraud events you wish to download, then select <strong>Add</strong>; several individual fraud types can be added to the request.</li><li><strong>Select Originating Country</strong> dropdown menu — select the country that the fraud events originated from, then select <strong>Add</strong>; several individual countries can be added to the request.</li><li><strong>From Date</strong> box — from the pop-up calendar, select the start date that the requested fraud events are filtered by; or enter the date manually in the <em>DD.MM.YYYY</em> format.</li><li><strong>To Date</strong> box — from the pop-up calendar, select the end date that the requested fraud events are filtered by; or enter the date manually in the <em>DD.MM.YYYY</em> format.</li></ul></li><li>Select <strong>Download</strong> to download the fraud events data filtered according to the data specified.</li></ol><p>For more information on fraud event data, including fraud identifiers, fraud types, and other relevant concepts, see <a href="./../overview/fraud-events.html">Fraud Events</a>.</p><h3 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h3><p>The fraud events data, filtered according to your specified criteria, is downloaded to your device as a .csv file, which can be opened using any spreadsheet software available to you (e.g., Microsoft Excel, Google Sheets); and the credit balance is decreased based on the current conversion rate active in the network (see <a href="./../overview/tokenomics.html#current-conversion-rate">Current conversion rate</a>).</p>',6),d=[n];function i(s,l,c,u,h,f){return t(),a("div",null,d)}const m=e(r,[["render",i]]);export{g as __pageData,m as default};
